    if self.urlfetch_retries and retries.raise_on_redirect:
        raise MaxRetryError(self, url, "too many redirects")
    else:
        if http_response.status == 303:
            method = "GET"

        try:
            retries = retries.increment(
                method, url, response=http_response, _pool=self
            )
